const meta = $input.first().json;
return DATASET.map(tc => ({
  json: {
    ...tc,
    run_id: meta.run_id,
    workflow_version: meta.workflow_version,
    model: meta.model
  }
}));

// Score each item. Input: HTTP response merged with test case metadata via $('code_load_dataset').
// Note: HTTP node emits items in same order as input, so we can zip by index.

const items = $input.all();
const testCases = $('code_load_dataset').all();

const results = items.map((item, idx) => {
  const tc = testCases[idx]?.json || {};
  const expect = tc.expect || {};

  let llmResponse = '';
  let parsedOutput = null;
  let tool_intention = null;
  let resposta_final = '';
  let reasoning = '';
  let parse_error = null;
  let http_error = null;

  // Extract OpenRouter response
  try {
    if (item.json?.error) {
      http_error = JSON.stringify(item.json.error).substring(0, 200);
    }
    llmResponse = item.json?.choices?.[0]?.message?.content || '';

    if (llmResponse) {
      // Strip markdown fences if any
      const cleaned = llmResponse.replace(/```json|```/g, '').trim();
      parsedOutput = JSON.parse(cleaned);
      tool_intention = parsedOutput.tool_intention;
      // Normalize "null" string to actual null
      if (tool_intention === 'null' || tool_intention === null || tool_intention === undefined) {
        tool_intention = null;
      }
      resposta_final = parsedOutput.resposta_final_simulada || '';
      reasoning = parsedOutput.reasoning_curto || '';
    }
  } catch(e) {
    parse_error = e.message;
    resposta_final = llmResponse;
  }

  // ============ SCORING ============
  const checks = {};

  // Check 1: non-empty response
  checks.non_empty = (resposta_final && resposta_final.toString().trim().length > 0);

  // Check 2: JSON parsed successfully
  checks.valid_json = (parse_error === null && http_error === null);

  // Check 3: tool correctness
  const expectedTools = expect.tools || [];
  const forbiddenTools = expect.forbidden_tools || [];
  let tool_correct = true;

  if (expectedTools.length === 0) {
    tool_correct = (tool_intention === null);
  } else {
    tool_correct = expectedTools.includes(tool_intention);
  }
  if (forbiddenTools.length > 0 && forbiddenTools.includes(tool_intention)) {
    tool_correct = false;
  }
  checks.tool_correct = tool_correct;

  // Check 4: keyword match (optional)
  if (expect.keywords && expect.keywords.length > 0) {
    const lower = (resposta_final || '').toLowerCase();
    checks.keyword_match = expect.keywords.some(k => lower.includes(k.toLowerCase()));
  } else {
    checks.keyword_match = null;
  }

  // Aggregate score
  const applicable = Object.values(checks).filter(v => v !== null);
  const passCount = applicable.filter(v => v === true).length;
  const ratio = applicable.length > 0 ? passCount / applicable.length : 0;

  let score = 0;
  if (http_error) score = 0;
  else if (ratio >= 0.99) score = 2;
  else if (ratio >= 0.5) score = 1;

  const status = score === 2 ? 'PASS' : score === 1 ? 'PARTIAL' : 'FAIL';

  return {
    json: {
      run_id: tc.run_id,
      workflow_version: tc.workflow_version,
      model: tc.model,
      timestamp: new Date().toISOString(),
      test_id: tc.id,
      category: tc.category,
      prompt: tc.prompt,
      success_criteria: tc.success_criteria,
      expect,
      llm_raw: (llmResponse || '').substring(0, 800),
      parsed: parsedOutput,
      tool_intention,
      resposta_final,
      reasoning,
      parse_error,
      http_error,
      checks,
      score,
      status
    }
  };
});

return results;

// Summary for immediate visibility in the execution log
const items = $input.all();
const total = items.length;
const pass = items.filter(i => i.json.status === 'PASS').length;
const partial = items.filter(i => i.json.status === 'PARTIAL').length;
const fail = items.filter(i => i.json.status === 'FAIL').length;
const runId = items[0]?.json?.run_id || 'unknown';
const passRate = total > 0 ? Math.round((pass / total) * 1000) / 10 : 0;

return [{
  json: {
    run_id: runId,
    total,
    pass,
    partial,
    fail,
    pass_rate_percent: passRate,
    message: `Run ${runId}: ${pass}/${total} PASS (${passRate}%), ${partial} PARTIAL, ${fail} FAIL`,
    next_step: 'Execute helena.eval.analyzer.json para analise detalhada'
  }
}];
